const acctResp = $('어제 계정 성과 조회').first().json;
const campResp = $('캠페인별 성과 조회').first().json;

const acctData = acctResp?.data?.[0] || null;
const campaigns = campResp?.data || [];

if (!acctData && campaigns.length === 0) {
  return [{ json: {
    hasData: false,
    message: '어제 Meta 광고 집행 데이터가 없습니다.'
  }}];
}

const spend = parseFloat(acctData?.spend || '0');
const impressions = parseInt(acctData?.impressions || '0');
const clicks = parseInt(acctData?.clicks || '0');
const ctr = parseFloat(acctData?.ctr || '0');
const cpc = parseFloat(acctData?.cpc || '0');
const reach = parseInt(acctData?.reach || '0');

const actions = acctData?.actions || [];
const purchases = actions.find(a => a.action_type === 'purchase');
const addToCart = actions.find(a => a.action_type === 'add_to_cart');
const linkClicks = actions.find(a => a.action_type === 'link_click');

const costPerAction = acctData?.cost_per_action_type || [];
const costPerPurchase = costPerAction.find(a => a.action_type === 'purchase');

let campLines = '';
for (const c of campaigns) {
  const ci = c.insights?.data?.[0];
  if (!ci) continue;
  const cSpend = parseFloat(ci.spend || '0');
  const cClicks = parseInt(ci.clicks || '0');
  const cImpr = parseInt(ci.impressions || '0');
  campLines += '  ' + c.name + ': ' + cSpend.toLocaleString() + '원';
  campLines += ' | ' + cImpr.toLocaleString() + '노출';
  campLines += ' | ' + cClicks + '클릭';
  campLines += '\n';
}

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toISOString().slice(0, 10);

let msg = '📊 *Meta Ads 일일 리포트*\n';
msg += dateStr + '\n\n';
msg += '💰 *계정 전체*\n';
msg += '  비용: ' + spend.toLocaleString() + '원\n';
msg += '  노출: ' + impressions.toLocaleString() + '\n';
msg += '  도달: ' + reach.toLocaleString() + '\n';
msg += '  클릭: ' + clicks.toLocaleString() + '\n';
msg += '  CTR: ' + ctr.toFixed(2) + '%\n';
msg += '  CPC: ' + cpc.toLocaleString() + '원\n';

if (purchases) {
  msg += '  구매: ' + purchases.value + '건\n';
  if (costPerPurchase) {
    msg += '  구매당 비용: ' + parseFloat(costPerPurchase.value).toLocaleString() + '원\n';
    const roas = purchases.value > 0 ? ((purchases.value * 30000) / spend * 100).toFixed(0) : '0';
    msg += '  추정 ROAS: ' + roas + '%\n';
  }
}

if (campLines) {
  msg += '\n📋 *캠페인별*\n' + campLines;
}

if (spend === 0) {
  msg += '\n⚠️ 어제 집행액 0원 — 캠페인이 일시정지 상태일 수 있습니다.';
}

return [{ json: { hasData: true, message: msg, spend, impressions, clicks } }];
